// ========================================================================
// v0.7 — Aufbereitung in zwei Output-Streams:
//   1) terms-Payload (genau 1 Item) → /api/untis-terms/sync
//   2) eintraege-Chunks (gechunked, max 4000 pro Call) → /api/deputate/sync-v2
//
// Der Workflow ruft (1) sequenziell vor (2) auf, damit der Untis-Terms-Master
// existiert bevor sync-v2 die FK-Constraint prueft.
// ========================================================================

const CONFIG = {
  apiKey: $env.STELLENIST_API_KEY || 'whk_55bc015c4fe7d9e3a7b9f4bcb6aad3b9fd5c4846cbd59662afc09f46d5708259',
  chunkSize: 4000, // sync-v2 erlaubt max 5000 — 4000 lassen Puffer
};

const inputItems = $input.all();
if (!inputItems || inputItems.length === 0) {
  return [{ json: { skip: true, reason: 'Keine Daten von MSSQL.' } }];
}

const today = new Date();
const sync_datum = `${today.getFullYear()}-${String(today.getMonth()+1).padStart(2,'0')}-${String(today.getDate()).padStart(2,'0')}`;

// ---- 1) Eindeutige Terms ableiten ----------------------------------------
const termsMap = new Map();
for (const item of inputItems) {
  const d = item.json;
  if (!d.SCHOOLYEAR_ID || !d.TERM_ID) continue;
  const key = `${d.SCHOOLYEAR_ID}_${d.TERM_ID}`;
  if (termsMap.has(key)) continue;
  termsMap.set(key, {
    school_year_id: parseInt(d.SCHOOLYEAR_ID, 10),
    term_id: parseInt(d.TERM_ID, 10),
    term_name: d.Term_Name ? String(d.Term_Name).substring(0, 50) : null,
    date_from: d.DateFrom_Formatted,
    date_to: d.DateTo_Formatted,
    is_b_period: d.IsBPeriode === 1 || d.IsBPeriode === true,
  });
}
const terms = [...termsMap.values()].sort((a, b) => {
  if (a.school_year_id !== b.school_year_id) return a.school_year_id - b.school_year_id;
  return a.term_id - b.term_id;
});

// ---- 2) Eintraege bauen (pro Lehrer × Periode) ---------------------------
const eintraege = [];
let schuljahrText = null;
for (const item of inputItems) {
  const d = item.json;
  if (!d.TEACHER_ID || !d.Vollname) continue;
  if (!schuljahrText) schuljahrText = d.Schuljahr_Text;
  eintraege.push({
    teacher_id: parseInt(d.TEACHER_ID, 10),
    name: String(d.Name).substring(0, 50),
    vollname: String(d.Vollname).substring(0, 200),
    personalnummer: d.Personalnummer ? String(d.Personalnummer).substring(0, 20).trim() : null,
    stammschule: String(d.Stammschule ?? '').substring(0, 10),
    statistik_code: d.Statistik_Code
      ? String(d.Statistik_Code).substring(0, 5).trim().toUpperCase()
      : null,
    school_year_id: parseInt(d.SCHOOLYEAR_ID, 10),
    term_id: parseInt(d.TERM_ID, 10),
    deputat_gesamt: Math.round((parseFloat(d.Deputat) || 0) * 1000) / 1000,
    deputat_ges: Math.round((parseFloat(d.Deputat_GES) || 0) * 1000) / 1000,
    deputat_gym: Math.round((parseFloat(d.Deputat_GYM) || 0) * 1000) / 1000,
    deputat_bk: Math.round((parseFloat(d.Deputat_BK) || 0) * 1000) / 1000,
  });
}

if (terms.length === 0 || eintraege.length === 0) {
  return [{ json: { skip: true, reason: 'Keine Terms oder Eintraege nach Aufbereitung.' } }];
}

// ---- Chunking der Eintraege ----------------------------------------------
const chunks = [];
for (let i = 0; i < eintraege.length; i += CONFIG.chunkSize) {
  chunks.push(eintraege.slice(i, i + CONFIG.chunkSize));
}

const outputs = [];

// (a) Erstes Item: Terms-Sync
outputs.push({
  json: {
    kind: 'terms',
    api_key: CONFIG.apiKey,
    sync_datum,
    terms,
    _info: {
      anzahl_terms: terms.length,
      anzahl_lehrer_eintraege_total: eintraege.length,
      anzahl_chunks: chunks.length,
    },
  },
});

// (b) Folgende Items: Eintraege-Chunks
chunks.forEach((chunk, idx) => {
  outputs.push({
    json: {
      kind: 'eintraege',
      api_key: CONFIG.apiKey,
      sync_datum,
      schuljahr_text: schuljahrText,
      eintraege: chunk,
      _info: {
        chunk_nr: idx + 1,
        chunk_total: chunks.length,
        anzahl_in_chunk: chunk.length,
      },
    },
  });
});

return outputs;
